      break;
    }
    case FriendResult.REMOVED:
      conn.friendStore.remove(packet.guid);
      break;
    // ... error cases
    default: {
      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
      conn.onFriendEvent?.({
        type: "friend-error",
        result: packet.result,
        name,
      });
