 260→  PLAYER_NO_MORE_IN_GUILD: 0x00,
 261→  GUILD_INTERNAL: 0x01,
 262→  ALREADY_IN_GUILD: 0x02,
 263→  ALREADY_IN_GUILD_S: 0x03,
 264→  INVITED_TO_GUILD: 0x04,
 265→  ALREADY_INVITED_TO_GUILD_S: 0x05,
 266→  GUILD_NAME_INVALID: 0x06,
 267→  GUILD_NAME_EXISTS_S: 0x07,
 268→  GUILD_LEADER_LEAVE_OR_PERMISSIONS: 0x08,
 269→  GUILD_PLAYER_NOT_IN_GUILD: 0x09,
 270→  GUILD_PLAYER_NOT_IN_GUILD_S: 0x0a,
 271→  GUILD_PLAYER_NOT_FOUND_S: 0x0b,
 272→  GUILD_NOT_ALLIED: 0x0c,
 273→  GUILD_RANK_TOO_HIGH_S: 0x0d,
 274→  GUILD_RANK_TOO_LOW_S: 0x0e,
 275→  GUILD_RANKS_LOCKED: 0x11,
 276→  GUILD_RANK_IN_USE: 0x12,
 277→  GUILD_IGNORING_YOU_S: 0x13,
 278→} as const;
 279→
 280→export type GuildCommandResultPacket = {
 281→  command: number;
 282→  name: string;
 283→  result: number;
 284→};
 285→
 286→export function parseGuildCommandResult(
 287→  r: PacketReader,
 288→): GuildCommandResultPacket {
 289→  return {
 290→    command: r.uint32LE(),
 291→    name: r.cString(),
 292→    result: r.uint32LE(),
 293→  };
 294→}
 295→
 296→export type GuildInvitePacket = {
 297→  inviterName: string;
 298→  guildName: string;
 299→};
 300→
 301→export function parseGuildInvitePacket(r: PacketReader): GuildInvitePacket {
 302→  return {
 303→    inviterName: r.cString(),
 304→    guildName: r.cString(),
 305→  };
 306→}
 307→
 308→export function formatGuildCommandError(
 309→  command: number,
 310→  name: string,
 311→  result: number,
 312→): string | undefined {
 313→  switch (result) {
 314→    case GuildCommandResult.PLAYER_NO_MORE_IN_GUILD:
 315→      return undefined;
 316→    case GuildCommandResult.GUILD_INTERNAL:
 317→      return "[guild] Internal guild error";
 318→    case GuildCommandResult.ALREADY_IN_GUILD:
 319→      return "[guild] You are already in a guild";
 320→    case GuildCommandResult.ALREADY_IN_GUILD_S:
 321→      return `[guild] ${name} is already in a guild`;
 322→    case GuildCommandResult.INVITED_TO_GUILD:
 323→      return "[guild] You have already been invited to a guild";
 324→    case GuildCommandResult.ALREADY_INVITED_TO_GUILD_S:
 325→      return `[guild] ${name} has already been invited to a guild`;
 326→    case GuildCommandResult.GUILD_NAME_INVALID:
 327→      return "[guild] Invalid guild name";
 328→    case GuildCommandResult.GUILD_NAME_EXISTS_S:
 329→      return `[guild] Guild name "${name}" already exists`;
 330→    case GuildCommandResult.GUILD_LEADER_LEAVE_OR_PERMISSIONS:
 331→      return "[guild] You don't have permission to do that";
 332→    case GuildCommandResult.GUILD_PLAYER_NOT_IN_GUILD:
 333→      return "[guild] You are not in a guild";
 334→    case GuildCommandResult.GUILD_PLAYER_NOT_IN_GUILD_S:
 335→      return `[guild] ${name} is not in your guild`;
 336→    case GuildCommandResult.GUILD_PLAYER_NOT_FOUND_S:
 337→      return `[guild] Player "${name}" not found`;
 338→    case GuildCommandResult.GUILD_NOT_ALLIED:
 339→      return `[guild] ${name} is not the same alliance as you`;
 340→    case GuildCommandResult.GUILD_RANK_TOO_HIGH_S:
 341→      return `[guild] ${name} has a rank too high for that`;
 342→    case GuildCommandResult.GUILD_RANK_TOO_LOW_S:
 343→      return `[guild] ${name} has a rank too low for that`;
 344→    case GuildCommandResult.GUILD_RANKS_LOCKED:
 345→      return "[guild] Guild ranks are locked";
 346→    case GuildCommandResult.GUILD_RANK_IN_USE:
 347→      return "[guild] That guild rank is in use";
 348→    case GuildCommandResult.GUILD_IGNORING_YOU_S:
 349→      return `[guild] ${name} is ignoring you`;
 350→    default:
 351→      return `[guild] Guild command error (${result})`;
 352→  }
 353→}
 354→```
